(()=>{"use strict";document.addEventListener("DOMContentLoaded",()=>{"undefined"!=typeof jQuery&&jQuery('[data-bs-toggle="tooltip"]').tooltip(),document.querySelectorAll('a[href^="#"]').forEach(e=>{e.addEventListener("click",function(e){e.preventDefault();const t=document.querySelector(this.getAttribute("href"));t&&t.scrollIntoView({behavior:"smooth"})})})})})();